package main

import (
	"fmt"

	"github.com/robertkrimen/otto"
)

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	if len(items) == 0 {
		return []map[string]interface{}{}, nil
	}

	// Initialize the Otto VM once to reuse it for all items.
	// Reusing the VM instance is significantly more performant than creating a new one inside the loop.
	vm := otto.New()

	// Pre-compile the condition script. This improves performance by parsing the
	// JavaScript code only once instead of re-parsing it for every item in the slice.
	compiledScript, err := vm.Compile("", conditionScript)
	if err != nil {
		return nil, err
	}

	// Pre-allocate the result slice with an initial capacity to minimize re-allocations.
	result := make([]map[string]interface{}, 0, len(items))

	for _, item := range items {
		// Inject the current item into the JavaScript environment as a global variable named 'item'.
		// Otto automatically maps Go map[string]interface{} to JavaScript objects.
		if err := vm.Set("item", item); err != nil {
			return nil, err
		}

		// Execute the pre-compiled script.
		// In JavaScript, the result of the last evaluated expression is returned as the value.
		value, err := vm.Run(compiledScript)
		if err != nil {
			return nil, err
		}

		// Convert the evaluation result to a boolean using JavaScript truthiness rules.
		// This correctly handles both explicit booleans and truthy/falsy values (e.g., 1, 0, null, "", "text").
		isMatch, err := value.ToBoolean()
		if err != nil {
			return nil, err
		}

		if isMatch {
			result = append(result, item)
		}
	}

	return result, nil
}

func main() {
	// Example data items
	items := []map[string]interface{}{
		{"id": 1, "name": "Apple", "active": true},
		{"id": 2, "name": "Banana", "active": false},
		{"id": 3, "name": "Cherry", "active": true},
		{"id": 4, "name": "Date", "active": 0}, // Falsy in JS
	}

	// Example script: filter for active items
	condition := "item.active == true"

	filtered, err := FilterItems(condition, items)
	if err != nil {
		fmt.Printf("Error filtering items: %v\n", err)
		return
	}

	fmt.Println("Filtered Items:")
	for _, item := range filtered {
		fmt.Printf("- ID: %v, Name: %v, Active: %v\n", item["id"], item["name"], item["active"])
	}
}

