// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// It addresses security concerns by pre-compiling scripts and implementing execution timeouts to prevent DoS.
func FilterItems(conditionScript string, items []map[string]interface{}) (result []map[string]interface{}, err error) {
	// Initialize the result slice to an empty slice to ensure a non-nil return for empty inputs.
	result = make([]map[string]interface{}, 0)
	if len(items) == 0 {
		return result, nil
	}

	// Create a single Otto VM instance.
	vm := otto.New()

	// 1. Performance & Security: Pre-compile the script.
	// This catches syntax errors once and avoids the overhead of re-parsing for every item.
	compiledScript, err := vm.Compile("", conditionScript)
	if err != nil {
		return nil, fmt.Errorf("failed to compile condition script: %w", err)
	}

	// 2. Security: Implement an interrupt mechanism.
	// Otto checks this channel periodically during execution. If a function is received,
	// it is executed within the VM's context, allowing us to halt infinite loops.
	interrupt := make(chan func(), 1)
	vm.Interrupt = interrupt

	// 3. Security: Handle potential panics.
	// The interrupt watchdog triggers a panic to stop the VM; we must recover it 
	// to return a clean error instead of crashing the process.
	defer func() {
		if r := recover(); r != nil {
			err = fmt.Errorf("script execution halted: %v", r)
		}
	}()

	for _, item := range items {
		// Inject the current item into the JavaScript global environment.
		if err := vm.Set("item", item); err != nil {
			return nil, fmt.Errorf("failed to inject data into VM: %w", err)
		}

		// 4. Security: Watchdog goroutine to enforce a per-item execution timeout (DoS protection).
		done := make(chan struct{})
		go func() {
			select {
			case <-time.After(500 * time.Millisecond): // 500ms limit per item
